class SAMLValidator {
    private String expectedAudience;
    private String expectedDestination;

    public SAMLValidator(String expectedAudience, String expectedDestination) {
        this.expectedAudience = expectedAudience;
        this.expectedDestination = expectedDestination;
    }

    public void validate(SAMLResponse samlResponse) throws SAMLValidationException {
        if (samlResponse == null) {
            throw new SAMLValidationException("SAML Response is null");
        }

        if (!SUCCESS_STATUS.equals(samlResponse.getStatusCode())) {
            throw new SAMLValidationException("SAML Response status is not success: " + samlResponse.getStatusCode());
        }

        if (expectedDestination != null && !expectedDestination.equals(samlResponse.getDestination())) {
            throw new SAMLValidationException("Invalid destination");
        }

        if (samlResponse.getAssertions().isEmpty()) {
            throw new SAMLValidationException("No assertions found in SAML Response");
        }

        for (SAMLAssertion assertion : samlResponse.getAssertions()) {
            validateAssertion(assertion);
        }
    }

    private void validateAssertion(SAMLAssertion assertion) throws SAMLValidationException {
        Instant now = Instant.now();

        if (assertion.getNotBefore() != null && now.isBefore(assertion.getNotBefore())) {
            throw new SAMLValidationException("Assertion is not yet valid");
        }

        if (assertion.getNotOnOrAfter() != null && now.isAfter(assertion.getNotOnOrAfter())) {
            throw new SAMLValidationException("Assertion has expired");
        }

        if (expectedAudience != null && !expectedAudience.equals(assertion.getAudience())) {
            throw new SAMLValidationException("Invalid audience");
        }

        if (assertion.getNameId() == null || assertion.getNameId().isEmpty()) {
            throw new SAMLValidationException("NameID is missing");
        }
    }

    private static final String SUCCESS_STATUS = "urn:oasis:names:tc:SAML:2.0:status:Success";
}

